import React, { useState } from "react";
import { motion } from "framer-motion";
import TestimonialCard from "./TestimonialCard";

const cardsData = [
  {
    title: "Frontend",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "list",
    backContent: [
      "Octavio Luna",
      "Leonardo Ibarra",
      "Leandro Colque",
      "Rodny Siles",
      "Kevin Sancalli",
      "Einar Guillen",
      "Huascar Duran",
      "Alejandro Zamorano",
    ],
  },
  {
    title: "Backend",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "list",
    backContent: [
      "Octavio Luna",
      "Leonardo Ibarra",
      "Leandro Colque",
      "Rodny Siles",
      "Kevin Sancalli",
      "Einar Guillen",
      "Huascar Duran",
      "Alejandro Zamorano",
    ],
  },
  {
    title: "Base de datos",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "list",
    backContent: [
      "Octavio Luna",
      "Leonardo Ibarra",
      "Leandro Colque",
      "Rodny Siles",
      "Kevin Sancalli",
      "Einar Guillen",
      "Huascar Duran",
      "Alejandro Zamorano",
    ],
  },
  {
    title: "Dashboard",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "list",
    backContent: [
      "Octavio Luna",
      "Leonardo Ibarra",
      "Leandro Colque",
      "Rodny Siles",
      "Kevin Sancalli",
      "Einar Guillen",
      "Huascar Duran",
      "Alejandro Zamorano",
    ],
  },
  {
    title: "Daniela Carolina Ovando Santander",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "image",
    backContent: "/media/aboutus/testimonial1.jpg", // reemplaza por ruta correcta
  },
  {
    title: "Jessica",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "image",
    backContent: "/media/aboutus/testimonial2.jpg", // reemplaza por ruta correcta
  },
  {
    title: "Guido",
    text: "Estamos dando unos retoques visuales estamos dando unos retoques visuales",
    role: "Desarrollador",
    backType: "image",
    backContent: "/media/aboutus/testimonial3.jpg", // reemplaza por ruta correcta
  },
];

const PersonalSection = () => {
  const [index, setIndex] = useState(0);

  const visibleCards = cardsData.slice(index, index + 4);

  const handleNext = () => {
    if (index + 4 < cardsData.length) setIndex(index + 1);
  };

  const handlePrev = () => {
    if (index > 0) setIndex(index - 1);
  };

  return (
    <section style={{ textAlign: "center", padding: "4rem 1rem" }}>
      <h2
        style={{
          fontSize: "2rem",
          fontWeight: "bold",
          color: "black",
          marginBottom: "2rem",
        }}
      >
        LOVED BY THOUSANDS
      </h2>

      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          gap: "1rem",
          flexWrap: "nowrap",
          overflow: "hidden",
        }}
      >
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handlePrev}
          style={{
            backgroundColor: "#154734",
            color: "#e4d0a9",
            width: 40,
            height: 40,
            borderRadius: "50%",
            fontSize: "1.5rem",
            border: "none",
            cursor: "pointer",
            userSelect: "none",
          }}
          disabled={index === 0}
        >
          ◀
        </motion.button>

        <div
          style={{
            display: "flex",
            gap: "1rem",
            overflow: "hidden",
            flexGrow: 1,
            justifyContent: "center",
          }}
        >
          {visibleCards.map((card, i) => (
            <TestimonialCard key={index + i} card={card} />
          ))}
        </div>

        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handleNext}
          style={{
            backgroundColor: "#154734",
            color: "#e4d0a9",
            width: 40,
            height: 40,
            borderRadius: "50%",
            fontSize: "1.5rem",
            border: "none",
            cursor: "pointer",
            userSelect: "none",
          }}
          disabled={index + 4 >= cardsData.length}
        >
          ▶
        </motion.button>
      </div>
    </section>
  );
};

export default PersonalSection;
